div.p:
Serialization barrier ensures all prior operations complete before drain operation executes.
Intel-grade Technical Specification for io_uring SQE Flags
| {near: top-center}

pre.code:
sqe_1: "0x00 | READ (fd=3) | addr=0x1000 | len=4K | flags=0" {
  style.fill: "#C5E8B7"
  shape: rectangle
  tooltip: "Op 1: Initial Read"
}
sqe_2: "0x40 | READ (fd=3) | addr=0x2000 | len=4K | flags=0" {
  style.fill: "#C5E8B7"
  shape: rectangle
  tooltip: "Op 2: Concurrent Read"
}
sqe_3: "0x80 | WRITE (fd=4) | addr=0x3000 | len=4K | flags=0" {
  style.fill: "#B8D4E8"
  shape: rectangle
  tooltip: "Op 3: Concurrent Write"
}
sqe_4: "0xC0 | READ (fd=5) | addr=0x4000 | len=4K | flags=0" {
  style.fill: "#C5E8B7"
  shape: rectangle
}
sqe_5: "0x100 | WRITE (fd=4) | addr=0x5000 | len=4K | flags=0" {
  style.fill: "#B8D4E8"
  shape: rectangle
}
sqe_6: "**0x140 | NOP | flags=IOSQE_IO_DRAIN**" {
  style.fill: "#FFE066"
  style.stroke: "#FF6B35"
  style.stroke-width: 4
  style.bold: true
  shape: rectangle
  tooltip: "Op 6: Serialization Point"
}

# Boundary annotations
sqe_1 -- sqe_2: "64B Boundary" {style.stroke-dash: 3; style.stroke: grey}
sqe_2 -- sqe_3: "64B Boundary" {style.stroke-dash: 3; style.stroke: grey}
sqe_3 -- sqe_4: "64B Boundary" {style.stroke-dash: 3; style.stroke: grey}
sqe_4 -- sqe_5: "64B Boundary" {style.stroke-dash: 3; style.stroke: grey}
sqe_5 -- sqe_6: "64B Boundary" {style.stroke-dash: 3; style.stroke: grey}

div.p:
kernel_logic: {
label: "Kernel Submission Path"
style.fill: "#FFF5E6"

pre.code:
wait_gate: "io_drain_wait_deps()" {
  shape: diamond
  style.fill: "#FFE4B5"
}

counter: "In-Flight Count: 5" {
  shape: rectangle
  style.fill: "#FFDAB9"
  style.stroke-dash: 2
}

wait_gate -> counter: "Check if == 0"

div.p:
sq_ring.sqe_6 -> kernel_logic.wait_gate: "Block Execution" {
style.stroke: "#FF6B35"
style.stroke-width: 2
style.animated: true
}
}

pre.code:
cqe_1: "0x00: CQE 1 | Res: 4096" {
  style.fill: "#90EE90"
  shape: rectangle
}
cqe_2: "0x10: CQE 2 | Res: 4096" {
  style.fill: "#90EE90"
  shape: rectangle
}
cqe_3: "0x20: CQE 3 | Res: 4096" {
  style.fill: "#87CEEB"
  shape: rectangle
}
cqe_4: "0x30: CQE 4 | Res: 4096" {
  style.fill: "#90EE90"
  shape: rectangle
}
cqe_5: "0x40: CQE 5 | Res: 4096" {
  style.fill: "#87CEEB"
  shape: rectangle
}
cqe_6: "**0x50: CQE 6 (DRAIN) | DISCHARGED**" {
  style.fill: "#FFE066"
  style.stroke: "#FF0000" # Red border to indicate focus
  style.stroke-width: 5
  style.bold: true
  shape: rectangle
}

cqe_1 -> cqe_2 -> cqe_3 -> cqe_4 -> cqe_5 -> cqe_6: {style.opacity: 0.1}

div.p:
retirement_logic: {
label: "Kernel Completion Path"
style.fill: "#F0FFF0"
gate_open: "io_cqring_ev_wait()\nBarrier Cleared" {
shape: rectangle
style.fill: "#98FB98"
style.bold: true
}
}
}

before -> barrier: "Queue Serialization\nEnforced" {
style.stroke: "#FF6B35"
style.stroke-width: 3
}

barrier -> after: "Discharge Op 6\nPost-Completion" {
style.stroke: "#FF6B35"
style.stroke-width: 3
}

timeline: {
label: "Temporal Execution Trace"
near: top-right

t1: "T1: SQE[1..5] Submitted" {
shape: circle
style.fill: "#2E86AB"
style.font-color: white
}
t2: "T2: SQE[6] Enqueued (DRAIN)" {
shape: circle
style.fill: "#FFB347"
}
t3: "T3: [1..5] Processing Completes" {
shape: circle
style.fill: "#FF6B35"
style.font-color: white
}
t4: "T4: SQE[6] Executed/Retired" {
shape: circle
style.fill: "#FFE066"
}

c
// C Implementation Example
"struct io_uring_sqe *sqe = io_uring_get_sqe(&ring);"
io_uring_prep_write(sqe, fd, buf, len, offset);

// Op 2: Serialization Point
"sqe = io_uring_get_sqe(&ring);"
io_uring_prep_nop(sqe);
sqe->flags |= IOSQE_IO_DRAIN;

row1: "Mode: Unordered Parallel Execution" {
style.fill: "#E8F5E9"
style.font-color: "#2E7D32"
}
row2: "Latency: ~120ns (Batch)" {
style.stroke-width: 0
}
row3: "Mode: IOSQE_IO_DRAIN Serialized" {
style.fill: "#FFEBEE"
style.font-color: "#C62828"
style.bold: true
}
row4: "Latency: ~840ns (Sync overhead)" {
style.stroke-width: 0
}
}

legend: {
label: "Resource Map"
near: bottom-left

read_op: "READ (Descriptor Data)" { style.fill: "#C5E8B7" }
write_op: "WRITE (Buffer Flush)" { style.fill: "#B8D4E8" }
drain_op: "DRAIN (Barrier SQE)" {
style.fill: "#FFE066"
style.stroke: "#FF6B35"
style.stroke-width: 2
}
cqe: "CQE (Completion Event)" { style.fill: "#90EE90" }
}
